const INCOME_THRESHOLD_VIP_BLOCK = 30_000_000;

function getMutationInfo(name) {
  return name ? MUTATIONS[name] : null;
}

function mapBrainrot(b) {
  return {
    id: b.id,
    name: b.name,
    rarity: b.rarity,
    income: b.income,
    cost: b.cost,
    value: b.cost || b.income,
    mutation: b.mutation || null,
    baseId: b.baseId || b.id,
  };
}

function applyMutationsToBase(brainrots) {
  const muts = Object.values(MUTATIONS).filter(m => m.id !== 'default');
  const out = [];
  for (const b of brainrots) {
    if (!b.income) continue;
    out.push(mapBrainrot({ ...b, mutation: null, baseId: b.id }));
    for (const mut of muts) {
      const income = Math.round(b.income * mut.multiplier);
      const cost = b.cost ? Math.round(b.cost * mut.multiplier) : null;
      const mutName = Object.keys(MUTATIONS).find(k => MUTATIONS[k].id === mut.id);
      out.push(mapBrainrot({
        id: b.id + '_' + mut.id,
        name: mutName + ' ' + b.name,
        rarity: b.rarity,
        income,
        cost,
        value: cost || income,
        mutation: mutName,
        baseId: b.id,
      }));
    }
  }
  return out;
}

async function loadBrainrots() {
  try {
    const [brRes, mutRes] = await Promise.all([
      fetch('parser/brainrots.json'),
      fetch('parser/mutations.json'),
    ]);
    if (brRes.ok) {
      const data = await brRes.json();
      const base = data.brainrots.filter(b => b.income != null && b.income > 0);
      BRAINROTS.length = 0;
      BRAINROTS.push(...applyMutationsToBase(base));
    }
    if (mutRes.ok) {
      const mData = await mutRes.json();
      for (const m of mData.mutations) {
        MUTATIONS[m.name] = { id: m.id, multiplier: m.multiplier, type: m.type, color: m.color };
      }
    }
  } catch {
    /* встроенный каталог */
  }
  return BRAINROTS;
}

function getBrainrot(id) {
  return BRAINROTS.find(b => b.id === id);
}

function getBrainrotByName(name) {
  const q = name.toLowerCase().trim();
  return BRAINROTS.find(b => b.name.toLowerCase() === q)
    || BRAINROTS.find(b => b.name.toLowerCase().includes(q));
}

function getRarityInfo(rarity) {
  return RARITY[rarity] || RARITY['Common'];
}

function formatValue(v) {
  if (!v) return '0';
  if (v >= 1e12) return (v / 1e12).toFixed(1) + 'T';
  if (v >= 1e9) return (v / 1e9).toFixed(1) + 'B';
  if (v >= 1e6) return (v / 1e6).toFixed(1) + 'M';
  if (v >= 1e3) return (v / 1e3).toFixed(1) + 'K';
  return String(Math.round(v));
}

function formatIncome(v) {
  if (!v) return '?';
  if (v >= 1e12) return (v / 1e12).toFixed(2) + 'T';
  if (v >= 1e9) return (v / 1e9).toFixed(2) + 'B';
  if (v >= 1e6) return (v / 1e6).toFixed(2) + 'M';
  if (v >= 1e3) return (v / 1e3).toFixed(1) + 'K';
  return String(v);
}

function calcUpgradeChance(fromIncome, toIncome) {
  if (!fromIncome || !toIncome || toIncome <= fromIncome) return 95;
  const ratio = fromIncome / toIncome;
  return Math.min(95, Math.max(0, ratio * 100 * 0.85));
}

function formatChance(ch) {
  if (ch == null || isNaN(ch)) return '—';
  const n = Number(ch);
  if (n <= 0) return '0%';
  if (n >= 10) {
    const s = Number.isInteger(n) ? String(n) : n.toFixed(4).replace(/\.?0+$/, '');
    return s + '%';
  }
  if (n >= 0.01) return parseFloat(n.toFixed(6)) + '%';
  if (n >= 1e-9) return parseFloat(n.toFixed(12)) + '%';
  return n.toExponential(4) + '%';
}

function formatChanceShort(ch) {
  const n = Number(ch);
  if (isNaN(n) || n <= 0) return '0%';
  if (n >= 1) return (Number.isInteger(n) ? n : parseFloat(n.toFixed(2))) + '%';
  if (n >= 0.01) return parseFloat(n.toFixed(4)) + '%';
  return n.toExponential(1) + '%';
}

function chanceToWheelDeg(chance) {
  return Math.max(0.25, chance / 100 * 360) + 'deg';
}

function rollToAngle(roll) {
  return roll * 3.6;
}
